chrome.runtime.onInstalled.addListener(()=>{chrome.contextMenus.create({id:"inline-root",title:"Inline",contexts:["selection"]}),chrome.contextMenus.create({id:"notes",parentId:"inline-root",title:"📝 Add Note",contexts:["selection"]}),chrome.contextMenus.create({id:"highlight",parentId:"inline-root",title:"🖊️ Highlight",contexts:["selection"]}),chrome.contextMenus.create({id:"rewrite",parentId:"inline-root",title:"✏️ Rewrite",contexts:["selection"]}),chrome.contextMenus.create({id:"ai",parentId:"inline-root",title:"✨ Ask AI",contexts:["selection"]})});chrome.contextMenus.onClicked.addListener((e,t)=>{!t?.id||e.menuItemId==="inline-root"||chrome.tabs.sendMessage(t.id,{type:"INLINE_FEATURE",featureId:e.menuItemId,selectedText:e.selectionText??""})});
